'use client';

import { useEffect, useState } from 'react';
import { useSearchParams } from 'next/navigation';
import Link from 'next/link';
import { useAuth } from '@/contexts/auth-context';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Skeleton } from '@/components/ui/skeleton';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  FileText,
  Plus,
  MagnifyingGlass,
  Eye,
  Funnel,
} from '@phosphor-icons/react';
import type { Application, ApplicationStatus } from '@/lib/types';
import { formatDistanceToNow } from 'date-fns';

interface EnrichedApplication extends Application {
  applicantName: string;
  applicantEmail: string;
  reviewerName: string | null;
  approverName: string | null;
}

const STATUS_OPTIONS: { value: ApplicationStatus | 'all'; label: string }[] = [
  { value: 'all', label: 'All Status' },
  { value: 'draft', label: 'Draft' },
  { value: 'submitted', label: 'Submitted' },
  { value: 'under_review', label: 'Under Review' },
  { value: 'additional_info_required', label: 'Additional Info Required' },
  { value: 'reviewed', label: 'Reviewed' },
  { value: 'approved', label: 'Approved' },
  { value: 'rejected', label: 'Rejected' },
];

export default function ApplicationsPage() {
  const { permissions } = useAuth();
  const searchParams = useSearchParams();
  const initialStatus = searchParams.get('status') as ApplicationStatus | null;

  const [applications, setApplications] = useState<EnrichedApplication[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>(initialStatus || 'all');

  useEffect(() => {
    async function fetchApplications() {
      try {
        const url = statusFilter && statusFilter !== 'all' 
          ? `/api/applications?status=${statusFilter}` 
          : '/api/applications';
        const response = await fetch(url);
        if (response.ok) {
          const data = await response.json();
          setApplications(data.applications || []);
        }
      } catch (error) {
        console.error('Failed to fetch applications:', error);
      } finally {
        setIsLoading(false);
      }
    }

    fetchApplications();
  }, [statusFilter]);

  const getStatusBadge = (status: ApplicationStatus) => {
    const config: Record<ApplicationStatus, { variant: 'default' | 'secondary' | 'destructive' | 'outline'; label: string; className?: string }> = {
      draft: { variant: 'outline', label: 'Draft' },
      submitted: { variant: 'secondary', label: 'Submitted' },
      under_review: { variant: 'default', label: 'Under Review', className: 'bg-blue-500' },
      additional_info_required: { variant: 'outline', label: 'Info Required', className: 'border-orange-500 text-orange-600' },
      reviewed: { variant: 'secondary', label: 'Reviewed', className: 'bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-200' },
      approved: { variant: 'default', label: 'Approved', className: 'bg-green-500' },
      rejected: { variant: 'destructive', label: 'Rejected' },
    };
    const { variant, label, className } = config[status];
    return <Badge variant={variant} className={className}>{label}</Badge>;
  };

  const filteredApplications = applications.filter((app) => {
    if (!searchQuery) return true;
    const query = searchQuery.toLowerCase();
    return (
      app.bankName.toLowerCase().includes(query) ||
      app.referenceNumber.toLowerCase().includes(query) ||
      app.applicantName.toLowerCase().includes(query) ||
      app.contactEmail.toLowerCase().includes(query)
    );
  });

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Applications</h1>
          <p className="text-muted-foreground">
            {permissions?.canViewAllApplications 
              ? 'All bank licensing applications' 
              : 'Your bank licensing applications'}
          </p>
        </div>
        {permissions?.canCreateApplication && (
          <Link href="/applications/new">
            <Button className="gap-2">
              <Plus size={16} weight="bold" />
              New Application
            </Button>
          </Link>
        )}
      </div>

      {/* Filters */}
      <Card>
        <CardContent className="pt-6">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-center">
            <div className="relative flex-1">
              <MagnifyingGlass className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
              <Input
                placeholder="Search by bank name, reference, or applicant..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-9"
              />
            </div>
            <div className="flex items-center gap-2">
              <Funnel className="h-4 w-4 text-muted-foreground" />
              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-[200px]">
                  <SelectValue placeholder="Filter by status" />
                </SelectTrigger>
                <SelectContent>
                  {STATUS_OPTIONS.map((option) => (
                    <SelectItem key={option.value} value={option.value}>
                      {option.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Applications Table */}
      <Card>
        <CardHeader>
          <CardTitle>
            {filteredApplications.length} Application{filteredApplications.length !== 1 ? 's' : ''}
          </CardTitle>
          <CardDescription>
            Click on an application to view details
          </CardDescription>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="space-y-4">
              {[...Array(5)].map((_, i) => (
                <div key={i} className="flex items-center gap-4">
                  <Skeleton className="h-12 w-12 rounded" />
                  <div className="space-y-2 flex-1">
                    <Skeleton className="h-4 w-48" />
                    <Skeleton className="h-3 w-32" />
                  </div>
                  <Skeleton className="h-6 w-24" />
                </div>
              ))}
            </div>
          ) : filteredApplications.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 text-center">
              <FileText className="h-12 w-12 text-muted-foreground/50 mb-4" />
              <p className="text-lg font-medium">No applications found</p>
              <p className="text-muted-foreground mt-1">
                {searchQuery || statusFilter !== 'all' 
                  ? 'Try adjusting your search or filters' 
                  : permissions?.canCreateApplication 
                    ? 'Create your first application to get started'
                    : 'No applications have been submitted yet'}
              </p>
              {permissions?.canCreateApplication && !searchQuery && statusFilter === 'all' && (
                <Link href="/applications/new" className="mt-4">
                  <Button className="gap-2">
                    <Plus size={16} />
                    Create Application
                  </Button>
                </Link>
              )}
            </div>
          ) : (
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Reference</TableHead>
                    <TableHead>Bank Name</TableHead>
                    <TableHead>Type</TableHead>
                    {permissions?.canViewAllApplications && <TableHead>Applicant</TableHead>}
                    <TableHead>Status</TableHead>
                    <TableHead>Submitted</TableHead>
                    <TableHead className="text-right">Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredApplications.map((app) => (
                    <TableRow key={app.id}>
                      <TableCell className="font-mono text-sm">{app.referenceNumber}</TableCell>
                      <TableCell className="font-medium">{app.bankName}</TableCell>
                      <TableCell className="capitalize">{app.bankType}</TableCell>
                      {permissions?.canViewAllApplications && (
                        <TableCell>
                          <div>
                            <div className="font-medium">{app.applicantName}</div>
                            <div className="text-xs text-muted-foreground">{app.applicantEmail}</div>
                          </div>
                        </TableCell>
                      )}
                      <TableCell>{getStatusBadge(app.status)}</TableCell>
                      <TableCell className="text-muted-foreground">
                        {app.submittedAt 
                          ? formatDistanceToNow(new Date(app.submittedAt), { addSuffix: true })
                          : 'Not submitted'}
                      </TableCell>
                      <TableCell className="text-right">
                        <Link href={`/applications/${app.id}`}>
                          <Button variant="ghost" size="sm" className="gap-2">
                            <Eye size={16} />
                            View
                          </Button>
                        </Link>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
